##### 2.1 WebSocket 服务测试
**文件**: `/dashboard/tests/unit/services/websocket.test.ts` (新建)

```typescript
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { DashboardWebSocket } from '@/services/websocket'

describe('DashboardWebSocket', () => {
  let ws: DashboardWebSocket
  let mockWebSocket: any

  beforeEach(() => {
    // Mock WebSocket
    mockWebSocket = {
      send: vi.fn(),
      close: vi.fn(),
      addEventListener: vi.fn(),
      removeEventListener: vi.fn()
    }
    global.WebSocket = vi.fn(() => mockWebSocket) as any

    ws = new DashboardWebSocket()
  })

  afterEach(() => {
    ws.disconnect()
  })

  it('应该成功连接', () => {
    ws.connect('ws://localhost:3000')
    expect(WebSocket).toHaveBeenCalledWith('ws://localhost:3000')
  })

  it('应该自动重连', async () => {
    ws.connect('ws://localhost:3000')

    // 模拟连接断开
    const onclose = mockWebSocket.addEventListener.mock.calls[0][1]
    onclose({ code: 1006 })

    // 等待重连延迟
    await new Promise(resolve => setTimeout(resolve, 1000))

    expect(WebSocket).toHaveBeenCalledTimes(2) // 原始连接 + 重连
  })

  it('应该发送心跳', (done) => {
    ws.connect('ws://localhost:3000')

    setTimeout(() => {
      expect(mockWebSocket.send).toHaveBeenCalledWith(
        JSON.stringify({ type: 'ping' })
      )
      done()
    }, 30000) // 30秒心跳
  })

  it('应该接收消息', () => {
    const handler = vi.fn()
    ws.on('agent.status_changed', handler)

    // 模拟接收消息
    const onmessage = mockWebSocket.addEventListener.mock.calls.find(
      call => call[0] === 'message'
    )[1]

    onmessage({ data: JSON.stringify({
      event: 'agent.status_changed',
      data: { agent: 'test', status: 'running' }
    })})

    expect(handler).toHaveBeenCalledWith({
      agent: 'test',
      status: 'running'
    })
  })
})
```

